import React, { useState, useEffect } from 'react';
import connect from '@vkontakte/vk-connect';
import View from '@vkontakte/vkui/dist/components/View/View';
import ScreenSpinner from '@vkontakte/vkui/dist/components/ScreenSpinner/ScreenSpinner';
import '@vkontakte/vkui/dist/vkui.css';
import './css/app.css';
import './css/dtp.css';
import Home from './panels/Home';
import FullHistory from './panels/FullHistory';
import {get_preview_report, getPrice, gibdd_history, old_history, preview_data} from "./api";
import MyChecks from "./panels/MyChecks";
import Comparison from "./panels/Comparison";
import Competitors from "./panels/Competitors";
import OldHistory from "./panels/OldHistory";

let app_id = 7138591
let group_id = 161851419

const App = () => {
	const [activePanel, setActivePanel] = useState('home');
	const [fetchedUser, setUser] = useState(null);
	const [popout, setPopout] = useState(<ScreenSpinner size='large' />); //<ScreenSpinner size='large' />
	const [previewData, setPreviewData] = useState(undefined);
	const [gibddHistory, setGibddHistory] = useState(undefined);
	const [number, setNumber] = useState('');
	const [isValidNumber, setIsValidNumber] = useState(true);
	const [isMobPlatform, setIsMobPlatform] = useState(false);
	const [previousPanel, setPreviousPanel] = useState('home');
	const [price, setPrice] = useState('99');
	const [previewDataPresent, setPreviewDataPresent] = useState(undefined);
	const [gibddHistoryPresent, setGibddHistoryPresent] = useState(undefined);
	const [isPreview, setIsPreview] = useState(false);
	const [idHistory, setIdHistory] = useState(0);
	const [oldHistoryArr, setOldHistoryArr] = useState(undefined);

	useEffect(() => {
		const urlParams = new URLSearchParams(window.location.search);
		const myParam = urlParams.get('vk_platform');
		app_id = urlParams.get('vk_app_id');
		console.log("app_id", app_id)
		myParam !== "desktop_web" && setIsMobPlatform(true)
		connect.subscribe((e) => {
			switch (e.detail.type) {
				case 'VKWebAppUpdateConfig':
					let schemeAttribute = document.createAttribute('scheme');
					schemeAttribute.value = e.detail.data.scheme ? e.detail.data.scheme : 'client_light';
					document.body.attributes.setNamedItem(schemeAttribute);
					break;
				case 'VKWebAppOpenPayFormResult':
					let result = e.detail.data.status
					console.log(result);
					if (e.detail.data.status) {
						gibdd_history(number, setGibddHistory, setPopout, setIsValidNumber, setActivePanel, setHeight, fetchedUser.id, setIsPreview)
					}
					break;
				case 'VKWebAppOpenPayFormFailed':
					setPopout(null)
					break;
				default:
					console.log(e.detail.type);
			}
		});
		async function fetchData() {
			const user = await connect.sendPromise('VKWebAppGetUserInfo');
			setUser(user);
			setPopout(null);
		}
		getPrice(setPrice)
		fetchData();
	}, []);

	const setHeight = (height) => {
		connect.send("VKWebAppResizeWindow", { "height": height});
	}


	const getPreviewData = () => {
		setPopout(<ScreenSpinner size='large' />)
		setPreviewData(undefined)
		setGibddHistory(undefined)
		preview_data(number, setPreviewData, setPopout, setIsValidNumber, setHeight, setIsPreview)
	};

	const getGibddHistory = () => {
		setPopout(<ScreenSpinner size='large' />)
		connect.send("VKWebAppOpenPayForm", {"app_id": app_id, "action": "pay-to-group", "params": {"amount" : price, "description" : `Оплата проверки автомобиля ${number > 11 ? "VIN" + number : "Гос номер:" + number}`, 'group_id' : group_id }});
	};

	const getOldHistory = () => {
			setPopout(<ScreenSpinner size='large' />)
			old_history(fetchedUser.id, setOldHistoryArr, setActivePanel, setPopout)
	};

	const getPreviewReport = () => {
		setIsPreview(true)
		if (previewDataPresent === undefined) {
			setPopout(<ScreenSpinner size='large' />)
			get_preview_report("О111ЕХ102", setPreviewDataPresent, setPopout, setHeight, setGibddHistoryPresent, setActivePanel)
		} else {
			setActivePanel('FullHistory')
		}
	}

	const changeNumber = (value) => {
		if (value.currentTarget.value) {
			setIsValidNumber(false)
			if (value.currentTarget.value.length === 17 ) { //если длина больше 10, то VIN
				 setIsValidNumber(true)
			} else {
				if (value.currentTarget.value.length < 11) {
					let re = /^[АВЕКМНОРСТУХ]\d{3}[АВЕКМНОРСТУХ]{2}\d{2,3}$/ui
					re.test(value.currentTarget.value) ? setIsValidNumber(true) : setIsValidNumber(false)
				}
			}
		} else {
			setIsValidNumber(true)
		}
		setNumber(value.currentTarget.value.toUpperCase())
	};


	const go = e => {
		setActivePanel(e.currentTarget.dataset.to);
	};


	return (
		<View activePanel={activePanel} popout={popout}>
			<Home id='home' fetchedUser={fetchedUser} go={go} previewData={previewData} setPopout={setPopout}
				  number={number} changeNumber={changeNumber} isValidNumber={isValidNumber}
				  getPreviewData={getPreviewData} getGibddHistory={getGibddHistory} isMobPlatform={isMobPlatform}
				  activePanel={activePanel} setActivePanel={setActivePanel} price={price} setPreviousPanel={setPreviousPanel}
			/>
			<FullHistory id='FullHistory' previousPanel={previousPanel} setActivePanel={setActivePanel} gibddHistory={gibddHistory} previewData={previewData}
						 isMobPlatform={isMobPlatform} previewDataPresent={previewDataPresent} gibddHistoryPresent={gibddHistoryPresent}
						 isPreview={isPreview} setIsPreview={setIsPreview} setHeight={setHeight}/>
			<MyChecks id='my-checks' activePanel={activePanel} setActivePanel={setActivePanel} setPreviousPanel={setPreviousPanel} getOldHistory={getOldHistory} setHeight={setHeight} oldHistoryArr={oldHistoryArr} popout={popout} setIdHistory={setIdHistory} />
			<Comparison id='comparison' activePanel={activePanel} setActivePanel={setActivePanel} setPreviousPanel={setPreviousPanel} isMobPlatform={isMobPlatform} getPreviewReport={getPreviewReport} price={price} setHeight={setHeight}/>
			<Competitors id='competitors' activePanel={activePanel} setActivePanel={setActivePanel} setPreviousPanel={setPreviousPanel} getPreviewReport={getPreviewReport} price={price} isMobPlatform={isMobPlatform} setHeight={setHeight}/>
			<OldHistory id='OldHistory' go={go} oldHistoryArr={oldHistoryArr} gibddHistory={gibddHistory}
						 isMobPlatform={isMobPlatform} idHistory={idHistory} setHeight={setHeight}/>
		</View>
	);
}

export default App;

