import React, {useEffect} from 'react';
import { Group, List} from '@vkontakte/vkui';
import Panel from '@vkontakte/vkui/dist/components/Panel/Panel';
import PanelHeader from '@vkontakte/vkui/dist/components/PanelHeader/PanelHeader';
import {Menu} from "../Menu";
import Avatar from "@vkontakte/vkui/dist/es6/components/Avatar/Avatar";
import Cell from "@vkontakte/vkui/dist/components/Cell/Cell";
import logo from "../img/logo.png"
import {getGibddHistoryDataArr} from "../util";
import Div from "@vkontakte/vkui/dist/es6/components/Div/Div";

const MyChecks = (props) => {
	const {id, activePanel, setActivePanel, setPreviousPanel,
		getOldHistory, setHeight, oldHistoryArr, popout, setIdHistory} = props

	useEffect(() => {
		setPreviousPanel(id)
		setHeight(2000)
		getOldHistory()
	}, []);

	useEffect(() => {
		setHeight(2000)
	}, [props]);


	return <Panel id={id}>
		<PanelHeader noShadow={true}>
			ГИБДД-проверка.рф
		</PanelHeader>
		<Menu activePanel={activePanel} setActivePanel={setActivePanel}/>
		{oldHistoryArr && oldHistoryArr.length > 0 ? <Group className='fix-menu-group'>
			{oldHistoryArr.map((auto, index) => <Cell
				before={<Avatar size={60} src={auto.imgs && getGibddHistoryDataArr(auto.imgs, "status") && auto.imgs.status === 200 && auto.imgs.photo.length > 0 ? auto.imgs.photo[0].src : logo}/>}
				expandable
				key={index}
				onClick={() => {
					setIdHistory(index)
					setActivePanel('OldHistory')
				}}
			>
				{getGibddHistoryDataArr(auto.history.gibdd_base.vehicle,"model") && auto.history.gibdd_base.vehicle.model}{getGibddHistoryDataArr(auto.history.gibdd_base.vehicle,"year") && ", " + auto.history.gibdd_base.vehicle.year} <br/>
				{getGibddHistoryDataArr(auto, "num") && <span>{"Гос. номер: " + auto.num}</span>} {getGibddHistoryDataArr(auto, "VIN") && <span>{"VIN: " + auto.VIN}</span>}
			</Cell> ) }<List>
			</List>
		</Group> : <Group className='fix-menu-group'><Div><p>{!popout && "Вы еще не делали проверок"}</p></Div></Group>}
	</Panel>
}

export default MyChecks;
